    public DateTime? EndedAt { get; private set; }

    public void Start()
    {
        if (Status != SessionStatus.Setup)
            throw new DomainException("Can only start from Setup");
        if (_players.Count < MinPlayers)
            throw new DomainException("Not enough players");
        Status = SessionStatus.Active;
        StartedAt = DateTime.UtcNow;
    }

    public void End()
    {
        if (Status != SessionStatus.Active)
            throw new DomainException("Can only end Active session");
        Status = SessionStatus.Completed;
        EndedAt = DateTime.UtcNow;
    }

    public void AddPlayer(SessionPlayer player)
    {
        if (Status != SessionStatus.Setup)
            throw new DomainException("Can only add players during Setup");
        if (_players.Count >= MaxPlayers)
            throw new DomainException("Session full");
        _players.Add(player);
    }
}
