// User aggregate methods
public class User : AggregateRoot<Guid>
{
    private List<OAuthAccount> _oauthAccounts = new();

    public void LinkOAuthAccount(string provider, string providerUserId)
    {
        if (_oauthAccounts.Any(a => a.Provider == provider))
            throw new DomainException("OAuth account already linked");

        _oauthAccounts.Add(new OAuthAccount(provider, providerUserId));
    }

    public void UnlinkOAuthAccount(string provider)
    {
        var account = _oauthAccounts.FirstOrDefault(a => a.Provider == provider);
        if (account == null)
            throw new DomainException("OAuth account not found");

        _oauthAccounts.Remove(account);
    }
}
